// Flutter imports:
import 'package:baseball_detector_flutter/providers/storefront_provider.dart';
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/constants.dart';
import 'package:baseball_detector_flutter/controllers/app_store_product_controller.dart';
import 'package:baseball_detector_flutter/controllers/subscription_controller.dart';
import 'package:baseball_detector_flutter/data/models/app_store_plan.dart';
import 'package:baseball_detector_flutter/data/models/team.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/utils/platform.dart';
import 'package:baseball_detector_flutter/utils/screen_orientation.dart';
import 'package:baseball_detector_flutter/utils/snack_bar.dart';
import 'package:baseball_detector_flutter/utils/storefront.dart';
import 'package:baseball_detector_flutter/utils/web_url.dart';
import 'package:baseball_detector_flutter/views/components/custom_loading_indicator.dart';
import 'package:baseball_detector_flutter/views/hooks/use_effect_once.dart';
import 'package:baseball_detector_flutter/views/hooks/use_privacy_policy.dart';
import 'package:baseball_detector_flutter/views/hooks/use_single_action.dart';
import 'package:baseball_detector_flutter/views/hooks/use_terms_of_use.dart';
import 'package:baseball_detector_flutter/views/pages/home/home_page.dart';
import 'package:baseball_detector_flutter/views/pages/home/hooks/use_subscription.dart';
import 'package:baseball_detector_flutter/views/pages/home/settings/hooks/use_plan_name.dart';
import 'package:baseball_detector_flutter/views/pages/home/settings/subscription/components/subscription_plan_card.dart';
import 'package:baseball_detector_flutter/views/themes/font_manager.dart';

class SubscriptionPage extends HookConsumerWidget {
  const SubscriptionPage({
    required this.team,
    this.currentPlan,
    super.key,
  });

  final Team team;
  final PlanType? currentPlan;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final theme = Theme.of(context);
    final cancelScheduledAt = team.teamPlanCancelAt;
    final downgradeScheduledAt = team.teamPlanDowngradeAt;

    final openTermsOfUse = useTermsOfUse();
    final openPrivacyPolicy = usePrivacyPolicy();

    final selectedPlan = useState<AppStoreProduct?>(null);
    final planName = usePlanNameFromPlanType(selectedPlan.value?.planType);
    final downgradePlanName = usePlanNameFromPlanId(team.downgradePlanId);
    final (canSubscribe, status, message) = useSubscription();

    final plans = ref.watch(appStoreProductControllerProvider);

    final storefront = ref.watch(storefrontProvider);

    // サブスクリプション設定（iOSの管理画面）を開く
    final openSubscriptionSettings =
        useSingleAction<void>(asyncCallback: (_) async {
      try {
        // TODO: Add Android implementation if needed
        if (isIos) {
          final appleUrl = Constants.appleSubscriptionURL;
          await openURLWithSystemBrowser(url: appleUrl);
        }
      } catch (e) {
        if (context.mounted) {
          context.showErrorSnackBar(
            context.l10n.cancel_subscription_page__error_opening_settings,
          );
        }
      }
    });

    useEffectOnce(
      () {
        return () => ScreenOrientation.setDefault();
      },
    );

    return Stack(
      children: [
        Scaffold(
          extendBodyBehindAppBar: true,
          appBar: AppBar(
            title: Text(
              context.l10n.subscription_page__select_best_plan,
              style: TextStyleManager.appBar.copyWith(
                color: theme.textTheme.headlineSmall?.color,
                fontWeight: FontWeight.bold,
              ),
            ),
            backgroundColor: Colors.transparent,
            elevation: 0,
            systemOverlayStyle: theme.brightness == Brightness.light
                ? SystemUiOverlayStyle.dark
                : SystemUiOverlayStyle.light,
            leading: IconButton(
              icon: Icon(Icons.close, color: theme.colorScheme.primary),
              onPressed: () => Navigator.of(context).pop(),
            ),
          ),
          body: Container(
            decoration: BoxDecoration(
              gradient: LinearGradient(
                begin: Alignment.topCenter,
                end: Alignment.bottomCenter,
                colors: [
                  theme.colorScheme.primary.withValues(alpha: 0.05),
                  theme.colorScheme.surface,
                ],
              ),
            ),
            child: Padding(
              padding: HomePage.bodyPadding,
              child: SafeArea(
                child: plans.when(
                  data: (plansList) => HookBuilder(builder: (context) {
                    // 現在の契約状況に基づいて初期選択プランを設定
                    useEffectOnce(() {
                      WidgetsBinding.instance.addPostFrameCallback((_) {
                        // 現在のプランより上位のプランを推奨として選択
                        final currentPlanIndex = currentPlan?.index;

                        final targetPlan = currentPlanIndex != null
                            ? plansList.where(
                                (e) => e.planType.index > currentPlanIndex)
                            : plansList.where((e) =>
                                e.planType ==
                                PlanType.standard); // デフォルトは Standard

                        if (targetPlan.isNotEmpty) {
                          selectedPlan.value = targetPlan.first;
                        }
                      });
                      return null;
                    });

                    // フッターリンク共通スタイルと要素ビルダー（折り返し対応）
                    final linkTextStyle = theme.textTheme.bodySmall?.copyWith(
                      color: theme.colorScheme.onSurfaceVariant,
                      decoration: TextDecoration.underline,
                    );
                    Widget buildLink(
                      String label,
                      VoidCallback onTap, {
                      bool withSeparator = false,
                    }) {
                      return Row(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          if (withSeparator) ...[
                            Text(
                              '|',
                              style: theme.textTheme.bodySmall?.copyWith(
                                color: theme.colorScheme.onSurfaceVariant,
                              ),
                            ),
                            const Gap(2),
                          ],
                          TextButton(
                            onPressed: onTap,
                            child: Text(
                              label,
                              style: linkTextStyle,
                            ),
                          ),
                        ],
                      );
                    }

                    return Column(
                      children: [
                        Expanded(
                          child: SingleChildScrollView(
                            child: Column(
                              mainAxisSize: MainAxisSize.max,
                              children: [
                                const Gap(12),
                                // プランカードを縦に並べて表示
                                ...plansList.map((plan) {
                                  final isDefaultPlan = currentPlan != null &&
                                      plan.planType == currentPlan;

                                  // PlanType に基づいてバッジタイプを決定
                                  final badgeType = switch (plan.planType) {
                                    PlanType.light => null,
                                    PlanType.standard =>
                                      SubscriptionBadgeType.recommended,
                                    PlanType.premium =>
                                      SubscriptionBadgeType.bestValue,
                                    PlanType.forMultipleTeam => null,
                                  };

                                  return Padding(
                                    padding: const EdgeInsets.only(bottom: 12),
                                    child: SubscriptionPlanCard(
                                      plan: plan,
                                      badgeType: badgeType,
                                      isSelected:
                                          selectedPlan.value?.planType ==
                                              plan.planType,
                                      isCurrentPlan: isDefaultPlan,
                                      cancelScheduledAt: isDefaultPlan
                                          ? cancelScheduledAt
                                          : null,
                                      downgradeScheduledAt: isDefaultPlan
                                          ? downgradeScheduledAt
                                          : null,
                                      downgradePlanName: isDefaultPlan
                                          ? downgradePlanName
                                          : null,
                                      onTap: () {
                                        HapticFeedback.lightImpact();
                                        selectedPlan.value = plan;
                                      },
                                    ),
                                  );
                                }),
                                const Gap(4),
                                Padding(
                                  padding: const EdgeInsets.symmetric(
                                      horizontal: 12),
                                  child: Text(
                                    context.l10n.subscription_page__usage_note,
                                    style: theme.textTheme.bodySmall?.copyWith(
                                      color: theme.colorScheme.onSurfaceVariant,
                                    ),
                                  ),
                                ),
                                if (!isStoreFrontUSA.value)
                                  TextButton(
                                    onPressed: openSubscriptionSettings,
                                    child: Text(
                                      context.l10n
                                          .subscription_page__cancel_subscription,
                                      style:
                                          theme.textTheme.bodySmall?.copyWith(
                                        color:
                                            theme.colorScheme.onSurfaceVariant,
                                        decoration: TextDecoration.underline,
                                      ),
                                    ),
                                  ),
                              ],
                            ),
                          ),
                        ),
                        Column(
                          mainAxisSize: MainAxisSize.min,
                          children: [
                            // US ストアフロント：Web 決済を優先
                            if (isStoreFrontUSA.value) ...[
                              SizedBox(
                                width: double.infinity,
                                height: 56,
                                child: ElevatedButton(
                                  onPressed: selectedPlan.value != null
                                      ? () async {
                                          try {
                                            final planManagementUrl =
                                                '${Constants.webURL}/account/plans';
                                            await openURLWithSystemBrowser(
                                              url: planManagementUrl,
                                            );
                                          } catch (e) {
                                            if (context.mounted) {
                                              context.showErrorSnackBar(
                                                context.l10n
                                                    .cancel_subscription_page__error_opening_settings,
                                              );
                                            }
                                          }
                                        }
                                      : null,
